using System.Data;
using Dapper;
using Valora.Application.Contracts;
namespace Valora.Infrastructure.Repositories;
public sealed class ResultRepository(IDbConnectionFactory f):IResultRepository{ public async Task<dynamic?> GetByResponseAsync(Guid responseId){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT * FROM valorapesquisa.result_scores WHERE response_id=@responseId",new{responseId});} public async Task SaveResultAsync(Guid organizationId,Guid responseId,decimal total,decimal max,decimal percentage,string maturityLabel,string radarText,string strategicTruth,string risk,string nextLevel,IDbTransaction tx){await tx.Connection!.ExecuteAsync("INSERT INTO valorapesquisa.result_scores(organization_id,response_id,total_score,max_score,percentage,maturity_label,radar_text,strategic_truth,risk_if_nothing_changes,next_level,devolutiva_json) VALUES (@organizationId,@responseId,@total,@max,@percentage,@maturityLabel,@radarText,@strategicTruth,@risk,@nextLevel,jsonb_build_object('source','public-api'))",new{organizationId,responseId,total,max,percentage,maturityLabel,radarText,strategicTruth,risk,nextLevel},tx);} public async Task SaveDimensionScoresAsync(Guid organizationId,Guid responseId,IEnumerable<dynamic> dims,IDbTransaction tx){foreach(var d in dims) await tx.Connection!.ExecuteAsync("INSERT INTO valorapesquisa.dimension_scores(organization_id,response_id,dimension_name,score,max_score,percentage,level_label) VALUES (@organizationId,@responseId,@DimensionName,@Score,@MaxScore,@Percentage,@LevelLabel)",new{organizationId,responseId,d.DimensionName,d.Score,d.MaxScore,d.Percentage,d.LevelLabel},tx);} public async Task<IReadOnlyList<dynamic>> GetDimensionsByResponseIdAsync(Guid responseId){using var c=f.Create(); return (await c.QueryAsync("SELECT * FROM valorapesquisa.dimension_scores WHERE response_id=@responseId ORDER BY dimension_name",new{responseId})).ToList();}}
